import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'



class GetUser extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, usersResult: [], selectedValue: "", lastSortColumn: "", lastSortOrder: 0
        };
    }

    handleOnClickColumn = (column) => {
      console.log(column)

      var lastSortOrder = this.state.lastSortOrder

      if (column === this.state.lastSortColumn) {
        if (lastSortOrder === 0) {
          lastSortOrder = 1
        } else {
          lastSortOrder = 0
        }
      } else {
        lastSortOrder = 0
      }

      var results = this.state.results

      if (lastSortOrder === 0) {
        results.sort(function(a,b) {
          var x = a[column].toLowerCase();
          var y = b[column].toLowerCase();
          return x < y ? -1 : x > y  ? 1: 0;
        })
      } else {
        results.sort(function(a,b) {
          var x = a[column].toLowerCase();
          var y = b[column].toLowerCase();
          return y < x ? -1 : y > x  ? 1: 0;
        })
      }




      //console.log(results)
      this.setState({lastSortColumn: column})
      this.setState({lastSortOrder: lastSortOrder})
      this.setState({results: results})

    }


    handleSelectChange = (selectedOptions) => {

        this.setState({screen: 0})
        this.setState({selectedValue: selectedOptions.value})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getVoalteUsers?name=` + selectedOptions.value, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({usersResult: response})

            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });



      }




      componentDidMount() {


        this.callVoalte("Providers Adult")

      }



      callVoalte = (name) => {


        this.setState({selectedValue: name})
        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `voalte?name=` + name, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})

            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }





          render() {


            var header = "Loading ..."







            if (this.state.screen === 1) {
              header = ""
              var content = []

/*
              const roleOption = []


              this.state.results.map(rec => {
                roleOption.push({value: rec.name, label: rec.name})
              })

              console.log(this.state.selectedValue)

              content.push(<div style={{marginTop: "5px", display: "block"}}><Select
              value={this.state.selectedValue}
              name="role"
              options={roleOption}
              className="basic-multi-select"
              classNamePrefix="select"
              onChange={this.handleSelectChange}
            /></div>)


              var tableContent = []

              if (this.state.selectedValue.length > 0) {

                tableContent.push(<tr><td colspan="3">Role: {this.state.selectedValue}</td></tr>)
              }
              this.state.usersResult.map(rec => {
                  console.log(rec)
                  tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}>{rec.first_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec.last_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec.email_address}</td></tr>)
              })

         */

              const roleOption = []



                roleOption.push({value: "Providers Adult", label: "Providers Adult"})
                roleOption.push({value: "Providers Pediatrics BCH Oak", label: "Providers Pediatrics BCH Oak"})
                roleOption.push({value: "Providers Pediatrics BCH SF", label: "Providers Pediatrics BCH SF"})
                roleOption.push({value: "Providers Periop/Anesthesia", label: "Providers Periop/Anesthesia"})
                roleOption.push({value: "Providers Radiology", label: "Providers Radiology"})
                roleOption.push({value: "Providers Surgery", label: "Providers Surgery"})
                roleOption.push({value: "Providers Womens", label: "Providers Womens"})

                const customStyles = {



                    control: css => ({
                    ...css,
                    width: 400,
                    }),
                    menu: ({ width, ...css }) => ({
                    ...css,
                    width: '400px',
                    minWidth: '20%',
                    }),
                    option: css => ({ ...css, width: 370 }),


                }



              content.push(<div style={{marginTop: "5px", display: "block"}}><Select
              value={{label: this.state.selectedValue, value: this.state.selectedValue}}
              name="role"
              options={roleOption}
              className="basic-multi-select"
              classNamePrefix="select"
              onChange={data => this.callVoalte(data.value)}
              width='400px'
              styles={customStyles}
            /></div>)


              //console.log(this.state.results)

            var tableContentformat = []

            var tableContent = []

            this.state.results.map(rec3 =>
                {
                    //content.push(<div><h2>{rec.building}</h2><hr></hr></div>)



                    /*
                    rec.unit.map(rec2 => {
                        //content.push(<div style={{marginTop: "20px"}}><h3>&nbsp;&nbsp;&nbsp;&nbsp;-- {rec2.unit}</h3></div>)

                        rec2.users.map(rec3 => {
                            tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}>{rec2.unit}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.last_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.first_name}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.email_address}</td><td style={{border: "1px solid", padding: "5px"}}>{rec3.role_name}</td></tr>)
                        })


                    })
                    */

                    var color = "black"
                    if (rec3.last_name === "- NOT FILLED") {
                      color = "red"
                    }

                    tableContent.push(<tr><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color}}>{rec3.unit}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color}}>{rec3.last_name}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color}}>{rec3.first_name}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color}}>{rec3.email_address}</span></td><td style={{border: "1px solid", padding: "5px"}}><span style={{color: color}}>{rec3.role_name}</span></td></tr>)


                  })

                  if (tableContent.length > 0) {
                    //&#x25B2; and &#x25BC;

                    var col1 = []
                    if (this.state.lastSortColumn === "unit") {
                      if (this.state.lastSortOrder === 0) {
                        col1.push("&#x25B2")
                      } else {
                        col1.push("&#x25BC")
                      }
                    }



                    tableContentformat.push(<tr><td style={{border: "1px solid", padding: "5px"}}>
                      <button type="button" onClick={data => this.handleOnClickColumn("unit")}>Role/Unit</button> {col1}
                  </td><td style={{border: "1px solid", padding: "5px"}}>
                        <button type="button" onClick={data => this.handleOnClickColumn("last_name")}>Last Name</button>
                  </td><td style={{border: "1px solid", padding: "5px"}}>
                        <button type="button" onClick={data => this.handleOnClickColumn("first_name")}>First Name</button>
                  </td>
                  <td style={{border: "1px solid", padding: "5px"}}>
                        <button type="button" onClick={data => this.handleOnClickColumn("email_address")}>Email</button>  
                  </td>
                  <td style={{border: "1px solid", padding: "5px"}}>
                        Role Name
                  </td>
                  </tr>)

                    tableContent.map(rec4 => {
                        tableContentformat.push(rec4)
                    })


                }



                content.push(<table style={{marginTop: "5px"}}>{tableContentformat}</table>)

          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default GetUser
